:root {
    --main-font: 'Spartan', sans-serif;
    --black: rgb(11, 3, 34);
    --red: rgb(110, 26, 26);
}

.main-text {
    font-family: var(--main-font);
    filter: drop-shadow(0.1em 0.1em 0.1em rgba(2, 23, 36, 0.2));
    color: var(--black);
    font-weight: bold;
    font-size: 20px;
}

