@import '../../common.css';

.modal_button {
    border-style: solid;
    width: 100px;
    font-size: 15px;
    font-weight: normal;
    padding: 0.5em;
    border-width: 2px;
    margin: auto;
    margin-bottom: 10px;
    border-radius: 10px;
    border-color: rgb(171, 152, 152);
    transition: background-color .5s ease-out;
    filter: drop-shadow(0.1em 0.1em 0.1em rgba(2, 23, 36, 0.2));
    cursor: pointer;
}

.modal_button_enable {
    background-color: rgba(110, 26, 26, 0.274);
}

.modal_button:hover {
    background-color: rgba(110, 26, 26, 0.274);
}
.modal_button:active {
    background-color: rgb(110, 26, 26);
}
.model_button-panel {
    left: 0;
    right: 0;
    margin: auto;
}
.model_margin {
    height: 25px;
}
.board-modal {
    position: fixed;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;
    margin: auto;
    width: 800px;
    height: 85%;
    text-align: center;
    cursor: default;
}

.board-modal_title {
    font-size: 30px;
}

.modal_line {
    font-weight: bold;
    padding: 2px;
    margin: auto;
    left: 0;
    right: 0;
    margin-bottom: 4px;
    filter: drop-shadow(0.1em 0.1em 0.1em rgba(2, 23, 36, 0.2));
}

.modal_number-button {
    width: 1.2em;
    margin-left: 1px;
    margin-right: 1px;
}
.inline {
    display: inline-block;
}
